import React, { useState } from 'react';
import { Lock, CheckCircle } from 'lucide-react';
import { supabase } from './lib/supabase';

export function SetPasswordPage() {
  const [password, setPassword] = useState('');
  const [loading, setLoading] = useState(false);
  const [success, setSuccess] = useState(false);
  const [error, setError] = useState('');

  const handleUpdatePassword = async (e: React.FormEvent) => {
    e.preventDefault();
    setLoading(true);
    setError('');

    const { error } = await supabase.auth.updateUser({
      password: password
    });

    if (error) {
      setError(error.message);
      setLoading(false);
    } else {
      await supabase.auth.signOut();
      
      setSuccess(true);
    }
  };

  if (success) {
    return (
      <div className="min-h-screen bg-[#121212] flex items-center justify-center p-4">
        <div className="bg-[#1a1a1a] border border-[#39FF14]/30 p-8 rounded-2xl max-w-md w-full text-center animate-in zoom-in duration-300">
          <CheckCircle className="w-16 h-16 text-[#39FF14] mx-auto mb-6" />
          <h2 className="text-2xl font-bold text-white mb-2">¡Contraseña Guardada!</h2>
          <p className="text-gray-400 mb-6">Tu cuenta está configurada correctamente.</p>
          <div className="bg-[#121212] border border-[#2a2a2a] p-4 rounded-xl">
            <p className="text-sm text-gray-300">
              Ya puedes cerrar esta ventana con seguridad e iniciar sesión en la aplicación móvil del gimnasio.
            </p>
          </div>
        </div>
      </div>
    );
  }

  return (
    <div className="min-h-screen bg-[#121212] flex items-center justify-center p-4">
      <div className="bg-[#1a1a1a] border border-[#2a2a2a] p-8 rounded-2xl max-w-md w-full shadow-2xl">
        <div className="text-center mb-8">
          <div className="w-12 h-12 bg-[#39FF14]/10 rounded-full flex items-center justify-center text-[#39FF14] mx-auto mb-4">
            <Lock size={24} />
          </div>
          <h2 className="text-2xl font-bold text-white">Configura tu cuenta</h2>
          <p className="text-gray-400 mt-2 text-sm">Crea una contraseña segura para acceder a tus entrenamientos y dieta.</p>
        </div>

        <form onSubmit={handleUpdatePassword} className="space-y-6">
          <div>
            <label className="text-xs text-gray-500 uppercase font-bold">Nueva Contraseña</label>
            <input 
              type="password" 
              required
              minLength={6}
              className="w-full bg-[#121212] border border-[#2a2a2a] p-3 rounded-xl mt-1 text-white focus:border-[#39FF14] outline-none"
              placeholder="Mínimo 6 caracteres..."
              value={password}
              onChange={(e) => setPassword(e.target.value)}
            />
          </div>

          {error && <p className="text-red-500 text-sm">{error}</p>}

          <button 
            type="submit" 
            disabled={loading}
            className="w-full py-3 bg-[#39FF14] text-black rounded-xl font-bold hover:bg-[#2EE010] transition-all disabled:opacity-50"
          >
            {loading ? 'Guardando...' : 'Guardar Contraseña'}
          </button>
        </form>
      </div>
    </div>
  );
}
